// Determinant returns the determinant computed in float64 by Gaussian
// elimination with partial pivoting.
func (m Matx33f) Determinant() float64 {
	var a [3][3]float64
	for i := 0; i < 3; i++ {
		for j := 0; j < 3; j++ {
			a[i][j] = float64(m[i*3+j])
		}
	}
	det := 1.0
	for col := 0; col < 3; col++ {
		p := col
		for rr := col + 1; rr < 3; rr++ {
			if matxAbs(a[rr][col]) > matxAbs(a[p][col]) {
				p = rr
			}
		}
		if a[p][col] == 0 {
			return 0
		}
		if p != col {
			a[p], a[col] = a[col], a[p]
			det = -det
		}
		det *= a[col][col]
		for rr := col + 1; rr < 3; rr++ {
			f := a[rr][col] / a[col][col]
			for cc := col; cc < 3; cc++ {
				a[rr][cc] -= f * a[col][cc]
			}
		}
	}
	return det
}

// Inverse returns the matrix inverse and true, or the zero matrix and
// false when the matrix is singular. Computation is in float64.
func (m Matx33f) Inverse() (Matx33f, bool) {
	var a [3][6]float64
	for i := 0; i < 3; i++ {
		for j := 0; j < 3; j++ {
			a[i][j] = float64(m[i*3+j])
		}
		a[i][3+i] = 1
	}
	for col := 0; col < 3; col++ {
		p := col
		for rr := col + 1; rr < 3; rr++ {
			if matxAbs(a[rr][col]) > matxAbs(a[p][col]) {
				p = rr
			}
		}
		if a[p][col] == 0 {
			var z Matx33f
			return z, false
		}
		a[p], a[col] = a[col], a[p]
		pv := a[col][col]
		for cc := 0; cc < 6; cc++ {
			a[col][cc] /= pv
		}
		for rr := 0; rr < 3; rr++ {
			if rr == col {
				continue
			}
			f := a[rr][col]
			for cc := 0; cc < 6; cc++ {
				a[rr][cc] -= f * a[col][cc]
			}
		}
	}
	var r Matx33f
	for i := 0; i < 3; i++ {
		for j := 0; j < 3; j++ {
			r[i*3+j] = float32(a[i][3+j])
		}
	}
	return r, true
}

